    // for the 4 runes case. So 7 runes is also no block. Confirmed.
    // 175 + 17.5 (first ins) + 5 = 197.5 → round up = 198
    expect(quote(Array.from({ length: 7 }, () => ({ type: "rune" })))).toBe(198);
  });
});

