// MHPCO Claim Office implementation

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface Customer {
  yearsWithMHPCO: number;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface DamageEntry {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: DamageEntry[];
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioOutput {
  results: StepResult[];
}

const PRICE_LIST: Record<string, { insurance: number; base: number; isComponent?: boolean }> = {
  sword:     { insurance: 1000, base: 100 },
  amulet:    { insurance:  600, base:  60 },
  staff:     { insurance:  800, base:  80 },
  potion:    { insurance:  400, base:  40 },
  rune:      { insurance:  250, base:  25, isComponent: true },
  moonstone: { insurance:  250, base:  25, isComponent: true },
};

const BLOCK_BASE = 60;
const PROCESSING_FEE = 5;
const DEDUCTIBLE = 100;

function priceOf(type: string): { insurance: number; base: number; isComponent?: boolean } {
  const entry = PRICE_LIST[type];
  if (!entry) throw new Error(`Unknown item type: ${type}`);
  return entry;
}

function isComponent(type: string): boolean {
  return PRICE_LIST[type]?.isComponent === true;
}

export function itemInsuranceValue(item: Item): number {
  return priceOf(item.type).insurance;
}

function itemBasePremium(item: Item): number {
  return priceOf(item.type).base;
}

function policyBasePremium(items: Item[]): number {
  // Components of the same type form a block discount when exactly 3 are present.
  const componentCounts: Record<string, number> = {};
  let total = 0;
  for (const it of items) {
    if (isComponent(it.type)) {
      componentCounts[it.type] = (componentCounts[it.type] ?? 0) + 1;
    } else {
      total += itemBasePremium(it);
    }
  }
  for (const type in componentCounts) {
    const n = componentCounts[type];
    total += n === 3 ? BLOCK_BASE : n * priceOf(type).base;
  }
  return total;
}

// Item-specific surcharges (cursed, high enchantment) apply to the item's
// individual base premium — for components, the per-item base (not the block price).
function itemSurcharge(item: Item): number {
  const base = itemBasePremium(item);
  const cursed = item.cursed ? base * 0.5 : 0;
  const highEnchant = (item.enchantment ?? 0) >= 5 ? base * 0.3 : 0;
  return cursed + highEnchant;
}

function sumItemSurcharges(items: Item[]): number {
  return items.reduce((sum, it) => sum + itemSurcharge(it), 0);
}

export interface QuoteContext {
  customer: Customer;
  isFirstContract: boolean; // true if this is the customer's first contract in scenario
}

export function computeQuote(items: Item[], ctx: QuoteContext): number {
  // Validate item types first
  for (const it of items) {
    if (!isKnownType(it.type)) {
      throw new Error(`Unknown item type: ${it.type}`);
    }
  }

  const basePolicy = policyBasePremium(items);
  const itemSurchargeTotal = allItemSurcharges(items);

  // First-insurance, loyalty, follow-up are policy-wide modifiers
  // applied to the policy base premium.
  const firstInsuranceSurcharge = basePolicy * 0.1;
  let loyaltyDiscount = 0;
  let followUpDiscount = 0;
  if (ctx.customer.yearsWithMHPCO >= 2) {
    loyaltyDiscount = basePolicy * 0.2;
  }
  if (!ctx.isFirstContract) {
    followUpDiscount = basePolicy * 0.15;
  }

  const subtotal =
    basePolicy +
    itemSurchargeTotal +
    firstInsuranceSurcharge -
    loyaltyDiscount -
    followUpDiscount;

  const totalWithFee = subtotal + PROCESSING_FEE;
  // Round up (in MHPCO favor for premiums)
  return Math.ceil(totalWithFee);
}

export interface Policy {
  items: Item[];
  insuranceSum: number;
  cap: number;
  remainingCap: number;
}

export function buildPolicy(items: Item[]): Policy {
  let insuranceSum = 0;
  for (const it of items) {
    insuranceSum += itemInsuranceValue(it);
  }
  const cap = insuranceSum * 2;
  return { items, insuranceSum, cap, remainingCap: cap };
}

export function processClaim(policy: Policy, incident: Incident): ClaimResult {
  // Validate damages
  // Count how many items of each type the policy covers
  const itemCounts: Record<string, number> = {};
  for (const it of policy.items) {
    itemCounts[it.type] = (itemCounts[it.type] ?? 0) + 1;
  }
  // Group damages by type
  const damageCounts: Record<string, number> = {};
  for (const d of incident.damages) {
    if (d.amount < 0) throw new Error(`Negative damage amount: ${d.amount}`);
    if (!isKnownType(d.itemType)) throw new Error(`Unknown item type in damage: ${d.itemType}`);
    damageCounts[d.itemType] = (damageCounts[d.itemType] ?? 0) + 1;
  }
  for (const t in damageCounts) {
    if ((itemCounts[t] ?? 0) < damageCounts[t]) {
      throw new Error(`Damage references items not on policy: ${t}`);
    }
  }

  // Map damages to specific items. Items of same type are interchangeable
  // for matching purposes; consume them in order.
  const usedByType: Record<string, number> = {};
  let totalPayout = 0;
  for (const d of incident.damages) {
    const t = d.itemType;
    const idxInType = usedByType[t] ?? 0;
    usedByType[t] = idxInType + 1;
    // Find the idxInType-th item of this type in the policy
    let found: Item | undefined;
    let seen = 0;
    for (const it of policy.items) {
      if (it.type === t) {
        if (seen === idxInType) {
          found = it;
          break;
        }
        seen++;
      }
    }
    if (!found) throw new Error("internal: matching item not found");

    let raw = d.amount;
    const dragon = found.material === "dragon";
    const highEnch = (found.enchantment ?? 0) >= 8;
    if (highEnch) {
      // 50% rule wins, even when dragon material also applies
      raw = d.amount * 0.5;
    } else if (dragon) {
      raw = d.amount;
    }
    const afterDeductible = raw - DEDUCTIBLE;
    if (afterDeductible > 0) totalPayout += afterDeductible;
  }

  // Round down (in MHPCO favor for payouts)
  let payout = Math.floor(totalPayout);

  // Apply cap
  if (payout > policy.remainingCap) payout = policy.remainingCap;
  policy.remainingCap -= payout;

  return { payout, remainingCap: policy.remainingCap };
}

export function runScenario(scenario: Scenario): ScenarioOutput {
  const results: StepResult[] = [];
  const policies: (Policy | undefined)[] = [];
  let quoteCount = 0;

  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === "quote") {
      const isFirstContract = quoteCount === 0;
      const premium = computeQuote(step.items, { customer: scenario.customer, isFirstContract });
      const policy = buildPolicy(step.items);
      policies[i] = policy;
      results.push({ premium });
      quoteCount++;
    } else if (step.op === "claim") {
      const policy = policies[step.policy];
      if (!policy) throw new Error(`Claim references missing policy index ${step.policy}`);
      const result = processClaim(policy, step.incident);
      results.push(result);
    } else {
      throw new Error(`Unknown op`);
    }
  }

  return { results };
}

